CREATE OR REPLACE FUNCTION f_gap_fill_update(tbl text, id text, row_num text) RETURNS void LANGUAGE plpgsql AS $func$
DECLARE
  tmp text[];
  col text;
BEGIN
  SELECT array(
    SELECT column_name
    FROM information_schema.columns
    WHERE table_name = tbl
      AND is_nullable = 'YES'
  ) INTO tmp;

  FOREACH col IN ARRAY tmp LOOP
    EXECUTE format(
      'UPDATE %I
       SET %I = c.last_value
       FROM (
         SELECT *, last_value(%I) OVER (PARTITION BY %I ORDER BY %I) AS last_value
         FROM %I
       ) AS c
       WHERE %I = c.%I AND %I = c.%I
         AND %I IS NULL AND c.last_value IS NOT NULL',
      tbl, col, col, id, row_num, tbl, id, id, row_num, row_num, col
    );
  END LOOP;
END;
$func$

