-- First, drop the existing function and aggregate if they exist
DROP AGGREGATE IF EXISTS GapFill(anyelement);
DROP FUNCTION IF EXISTS GapFillInternal(anyelement, anyelement);

-- Create the corrected GapFillInternal function
CREATE OR REPLACE FUNCTION GapFillInternal(s anyelement, v anyelement) RETURNS anyelement AS $$
BEGIN
    IF v IS NOT NULL THEN
        RETURN v;
    ELSE
        RETURN s;
    END IF;
END;
$$ LANGUAGE PLPGSQL;

-- Create the aggregate function
CREATE AGGREGATE GapFill(anyelement) (
    SFUNC = GapFillInternal,
    STYPE = anyelement
);

