CREATE OR REPLACE FUNCTION check_business_category_flag()
RETURNS TRIGGER AS $$
BEGIN
    -- Check if the referenced EventCategory has IsBusinessCategory set to true
    IF NOT EXISTS (
        SELECT 1 FROM "EventCategories" 
        WHERE "ID" = NEW."BusinessCategoryID" 
        AND "IsBusinessCategory" = true
    ) THEN
        RAISE EXCEPTION 'BusinessCategoryID % cannot reference EventCategory % because IsBusinessCategory is not true',
            NEW."BusinessCategoryID", NEW."BusinessCategoryID";
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

