CREATE OR REPLACE FUNCTION FIND_TEST_TABLE_COLUMN(
    IN_COLUMN1 VARCHAR,
    IN_COLUMN2 VARCHAR,
    IN_COLUMN3 VARCHAR,
    IN_COLUMN4 VARCHAR,
    IN_REQUESTED_COLUMN VARCHAR
) RETURNS VARCHAR AS $$
DECLARE
    C_TEST_TABLE_REC RECORD;
    RESULT VARCHAR(255);
    query TEXT;
BEGIN
    query := 'SELECT * FROM test_table WHERE column1 = $1 AND column2 = $2 AND column3 = $3';
    IF IN_COLUMN4 IS NOT NULL THEN
        query := query || ' AND column4 = $4';
    END IF;
    query := query || ' LIMIT 1';

    IF IN_COLUMN4 IS NOT NULL THEN
        EXECUTE query USING IN_COLUMN1, IN_COLUMN2, IN_COLUMN3, IN_COLUMN4 INTO C_TEST_TABLE_REC;
    ELSE
        EXECUTE query USING IN_COLUMN1, IN_COLUMN2, IN_COLUMN3 INTO C_TEST_TABLE_REC;
    END IF;

    IF NOT FOUND THEN
        RETURN NULL;
    END IF;

    IF IN_REQUESTED_COLUMN = 'COLUMN1' THEN
        RESULT := C_TEST_TABLE_REC.column1;
    ELSIF IN_REQUESTED_COLUMN = 'COLUMN2' THEN
        RESULT := C_TEST_TABLE_REC.column2;
    ELSIF IN_REQUESTED_COLUMN = 'COLUMN3' THEN
        RESULT := C_TEST_TABLE_REC.column3;
    ELSE
        RESULT := NULL;
    END IF;

    RETURN RESULT;
END;
$$ LANGUAGE plpgsql

